INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '15', 'US', 'Strato di limo e sabbia, di potenza variabile, mediamente di circa 0,6 m, colore grigio scuro e consistenza mediamente compatta. Livello fortemente antropicizzato, con frammenti laterizi e ceramici attribuibili genericamente all''età tardo romana. Il livello presenta una certa pendenza, degradando da O verso E e non è stato mai intercettato alla quota di sbancamento. Lo scavo parziale del deposito attraverso saggi, ha restituito reperti metallici, elementi lapidei, tessere musive e un buon numero di frammenti ceramici, databili, ad una prima analisi, tra V e VI sec. d.C.', '1', '', '[[''Coperto da'', ''12''], [''Coperto da'', ''13''], [''Coperto da'', ''16''], [''Coperto da'', ''284''], [''Coperto da'', ''289''], [''Coperto da'', ''344''], [''Coperto da'', ''436''], [''Coperto da'', ''441''], [''Coperto da'', ''443''], [''Coperto da'', ''488''], [''Coperto da'', ''492''], [''Copre'', ''379''], [''Tagliato da'', ''181''], [''Tagliato da'', ''192''], [''Tagliato da'', ''220''], [''Tagliato da'', ''241''], [''Tagliato da'', ''27''], [''Tagliato da'', ''274''], [''Tagliato da'', ''279''], [''Tagliato da'', ''281''], [''Tagliato da'', ''283''], [''Tagliato da'', ''30''], [''Tagliato da'', ''308''], [''Tagliato da'', ''310''], [''Tagliato da'', ''312''], [''Tagliato da'', ''316''], [''Tagliato da'', ''318''], [''Tagliato da'', ''320''], [''Tagliato da'', ''322''], [''Tagliato da'', ''324''], [''Tagliato da'', ''327''], [''Tagliato da'', ''33''], [''Tagliato da'', ''333''], [''Tagliato da'', ''346''], [''Tagliato da'', ''348''], [''Tagliato da'', ''35''], [''Tagliato da'', ''351''], [''Tagliato da'', ''36''], [''Tagliato da'', ''361''], [''Tagliato da'', ''365''], [''Tagliato da'', ''369''], [''Tagliato da'', ''37''], [''Tagliato da'', ''371''], [''Tagliato da'', ''373''], [''Tagliato da'', ''39''], [''Tagliato da'', ''396''