INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '397', 'US', 'Strato a matrice limo sabbiosa di colore marrone chiaro e consistenza friabile, con laterizi in frammenti, ciottoli fluviali, pietre di piccole e medie dimensioni e lenti di malta, sia sciolta che in grumi, individuato nel Settore 2 presso la struttura abitativa CAS-1. Il deposito è stato parzialemente asportato tramite mezzo meccanico in fase di sbancamento, successivamente rimosso stratigraficamente. Lo scavo manuale ha restituto numerosi frammenti di fauna, reperti metallici, tra cui due monete, e frammenti ceramici che, ad una prima analisi, mostrano una cronologia massima di XIV secolo', '1', '', '[[''Coperto da'', ''11''], [''Coperto da'', ''491''], [''Copre'', ''266''], [''Copre'', ''267''], [''Copre'', ''268''], [''Copre'', ''269''], [''Copre'', ''270''], [''Copre'', ''434''], [''Copre'', ''435''], [''Copre'', ''439''], [''Copre'', ''440''], [''Copre'', ''441''], [''Copre'', ''492''], [''Copre'', ''517''], [''Copre'', ''532''], [''Copre'', ''533''], [''Tagliato da'', ''274''], [''Tagliato da'', ''276''], [''Tagliato da'', ''395''], [''Tagliato da'', ''406''], [''Tagliato da'', ''408''], [''Tagliato da'', ''410''], [''Tagliato da'', ''445''], [''Tagliato da'', ''446''], [''Tagliato da'', ''453''], [''Uguale a'', ''250''], [''Uguale a'', ''436''], [''Uguale a'', ''451'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '241', 'US', 'Taglio di forma irregolare, con andamento subcircolare nella porzione NO, più rettilineo procedendo verso SE. Il taglio non conserva i suoi limiti originari in quanto tagliato dalla fondazione di una fossa da grano (STR. 19) e dalla sua fossa di spoliazione nella parte NO. Le pareti, visibili unicamente nella porzione SE  non occupata dalle pareti della STR. 18, presentano un andamento pressochè verticale, mentre il fondo, dove visibile è piatto', '1', '1', '[[''Riempito da'', ''242''], [''Riempito da'', ''671''], [''Riempito da'', ''672''], [''Riempito da'', ''691''], [''Riempito da'', ''701''], [''Riempito da'', ''711''], [''Riempito da'', ''714''], [''Riempito da'', ''715''], [''Riempito da'', ''716''], [''Riempito da'', ''717''], [''Riempito da'', ''718''], [''Riempito da'', ''726''], [''Riempito da'', ''728''], [''Riempito da'', ''729''], [''Riempito da'', ''730''], [''Riempito da'', ''733''], [''Riempito da'', ''734''], [''Riempito da'', ''735''], [''Riempito da'', ''736''], [''Si lega a'', ''712''], [''Taglia'', ''15''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723''], [''Uguale a'', ''712'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '567', 'US', 'Strato fortemente antropico costituito da due livelli ben distinguibili a matrice limo sabbiosa di colore grigio scuro, con lenti di cenere e di argilla depurata di colore verdastro, ricco di frustoli di carbone, frammenti ceramici, soprattutto anforacei, vetro, fauna, frammenti laterizi  e pietre di piccole e medie dimensioni (567a, 567c), intervallati da un sottile strato di malta poco compatta, di colore marrone chiaro. Lo strato, inizialmente individuato in sezione a seguito dell''asportazione del riempimento di una buca (US 552) e successivamente asportato in maniera stratigrafica, è stato documentato tra le STR. 15 e 16 e a SE rispetto alla STR. 15. La potenza massima del deposito è pari a 0.67 m. Lo scavo ha restituito fauna, frammenti di vetro, reperti in metallo tra cui numerosi nummi e una moneta ostrogota (RA 382) e una grande quantità di frammenti ceramici che, ad una prima analisi, presentano una datazionecompresa tra V e VII secolo. In corso di scavo sono stati individuati livelli diferenti (A, B, C), asportati stratigraficamente, ma con lo studio preliminare del materiale raccolto sono stati rinvenuti frammenti combacianti pertinenti a livelli differenti.', '2', '', '[[''Coperto da'', ''492''], [''Coperto da'', ''566''], [''Coperto da'', ''771''], [''Coperto da'', ''773''], [''Coperto da'', ''825''], [''Copre'', ''709''], [''Copre'', ''756''], [''Copre'', ''816''], [''Copre'', ''840''], [''Si appoggia a'', ''497''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''591''], [''Si appoggia a'', ''758''], [''Si appoggia a'', ''792''], [''Si appoggia a'', ''797''], [''Tagliato da'', ''496''], [''Tagliato da'', ''553''], [''Tagliato da'', ''561''], [''Tagliato da'', ''588''], [''Tagliato da'', ''764''], [''Tagliato da'', ''800''], [''Tagliato da'', ''813''], [''Tagliato da'', ''827''], [''Tagliato da'', ''829'']]');
