INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '34', 'US', 'Strato individuato per tutta l’estensione del Settore 2. Esso presenta una matrice limo-sabbiosa grigia e consistenza compatta, con frustoli di carbone e cenere in dispersione; risulta caratterizzato dalla presenza di frammenti di laterizi, pietre, grumi di malta e di numerosi frammenti ceramici di epoca tardo medievali (graffita, invetriata, maiolica arcaica) e post medievali, databili tra XIV e XVII secolo. Lo strato non conserva i limiti originari in quanto tagliato dalle fondazioni attribuibili alle case Succi-Paccini, oltre che da altre evidenze negative e da numerosi sottoservizi ', '2', '2', '[[''Coperto da'', ''10''], [''Coperto da'', ''50''], [''Coperto da'', ''52''], [''Copre'', ''54''], [''Copre'', ''59''], [''Copre'', ''64''], [''Copre'', ''65''], [''Tagliato da'', ''33''], [''Tagliato da'', ''37''], [''Tagliato da'', ''39''], [''Tagliato da'', ''41''], [''Tagliato da'', ''43''], [''Tagliato da'', ''45''], [''Tagliato da'', ''49''], [''Tagliato da'', ''53''], [''Tagliato da'', ''56''], [''Tagliato da'', ''58''], [''Tagliato da'', ''71''], [''Tagliato da'', ''73''], [''Tagliato da'', ''8''], [''Tagliato da'', ''86''], [''Tagliato da'', ''88''], [''Tagliato da'', ''91'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '612', 'US', 'Strato a matrice sabbiosa di colore marrone chiaro/rosato e consistenza poco compatta con un''alta percentale di malta, sia sciolta e in grumi e laterizi in frammenti, soprattutto tegole e tuboli. L''evidenza è stata individuata durante l''ampliamento in direzione NO del Saggio 13, e successivamente indagata in maniera estensiva a seguito dell''allargamento dell''area di scavo finalizzata all''individuazione dell''estensione dell''ambiente termale STR. 29. Il deposito ha una potenza massima di 1.18 m e non conserva i limiti originari', '2', '', '[[''Coperto da'', ''492''], [''Copre'', ''807''], [''Copre'', ''808''], [''Copre'', ''809''], [''Copre'', ''810''], [''Si appoggia a'', ''538''], [''Si appoggia a'', ''606''], [''Si appoggia a'', ''613''], [''Si appoggia a'', ''779''], [''Si appoggia a'', ''780''], [''Si appoggia a'', ''781''], [''Si appoggia a'', ''783''], [''Si appoggia a'', ''789''], [''Si appoggia a'', ''801''], [''Si appoggia a'', ''802''], [''Tagliato da'', ''579''], [''Tagliato da'', ''625''], [''Tagliato da'', ''703''], [''Tagliato da'', ''725'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '1', 'US', 'Strato di asfalto contemporaneo con un sottofondo costituito da conglomerato molto compatto di colore grigio chiaro, o rivestimento in sampietrini legati con malta, invenuto nell''intera area indagata di Piazza Malatesta', '1', '', '[[''Copre'', ''108''], [''Copre'', ''109''], [''Copre'', ''120''], [''Copre'', ''124''], [''Copre'', ''126''], [''Copre'', ''128''], [''Copre'', ''136''], [''Copre'', ''140''], [''Copre'', ''141''], [''Copre'', ''142''], [''Copre'', ''145''], [''Copre'', ''18''], [''Copre'', ''2''], [''Copre'', ''79''], [''Copre'', ''80''], [''Copre'', ''81''], [''Copre'', ''95''], [''Copre'', ''98''], [''Si appoggia a'', ''74''], [''Si appoggia a'', ''75''], [''Si appoggia a'', ''76''], [''Si appoggia a'', ''77''], [''Si appoggia a'', ''78'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '498', 'USM', 'Struttura con andamento NO/SE, individuata in prossimità del limite NO del Settore 2b, realizzata in laterizi, raramente integri e posto sia di testa che di lista, legati con malta mediamente tenace di colore giallastro, con inclusi millimetrici e centimetrici e posti su filari orizzontali, piuttosto regolari e quasi privi di inzeppature. Il muro si lega a S con US 497 e a N gli si appoggia US 538 e si conserva per 11 corsi regolari, per un''altezza totale di 0.8 m, di dimensioni pari a 0.45 m di larghezza 2.10 m di lunghezza, per un''altezza complessiva documentata di 1 m. Data la frammentarietà dei mattoni, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 7 cm, la lunghezza varia da 27 a 30 cm, mentre la larghezza da 12 a 14 cm. Tra le tipologie documentate in corso di scavo, l''USM 498 è riferibile alla 1a', '1', '2', '[[''Coperto da'', ''292''], [''Copre'', ''758''], [''Gli si appoggia'', ''349''], [''Gli si appoggia'', ''510''], [''Gli si appoggia'', ''555''], [''Gli si appoggia'', ''567''], [''Gli si appoggia'', ''568''], [''Gli si appoggia'', ''569''], [''Gli si appoggia'', ''570''], [''Gli si appoggia'', ''572''], [''Gli si appoggia'', ''574''], [''Si appoggia a'', ''591''], [''Si appoggia a'', ''606''], [''Si lega a'', ''497''], [''Si lega a'', ''500''], [''Tagliato da'', ''561''], [''Tagliato da'', ''579'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '96', 'US', 'Strato a matrice limo argillosa di colore marrone e consistenza compatta, con ciottoli fluviali di piccole e medie dimensioni, laterizi in frammenti, frustoli di carbone e reperti osteologici umani non in connessione', '3', '', '[[''Coperto da'', ''2''], [''Copre'', ''471''], [''Copre'', ''521''], [''Copre'', ''522''], [''Copre'', ''524''], [''Copre'', ''525''], [''Copre'', ''530''], [''Copre'', ''855''], [''Copre'', ''97''], [''Si appoggia a'', ''854''], [''Tagliato da'', ''102''], [''Tagliato da'', ''104''], [''Tagliato da'', ''111''], [''Tagliato da'', ''125''], [''Tagliato da'', ''127''], [''Tagliato da'', ''129''], [''Tagliato da'', ''131''], [''Tagliato da'', ''133''], [''Tagliato da'', ''135''], [''Tagliato da'', ''137'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '586', 'US', 'Strato a matrice argillosa di colore marrone e consistenza molto compatta con malta sciolta e in grumi, laterizi in frammenti, sporadiche pietre e ciottoli fluviali di piccole dimensioni, con andamento tabulare, individuato a S della STR. 16 e scavato solo durante interventi puntuali di pulizia del muro S della stessa (US 590)', '1', '', '[[''Coperto da'', ''491''], [''Coperto da'', ''623''], [''Copre'', ''590''], [''Copre'', ''595''], [''Copre'', ''597''], [''Copre'', ''601''], [''Copre'', ''602''], [''Copre'', ''614''], [''Copre'', ''617''], [''Copre'', ''629''], [''Copre'', ''649''], [''Copre'', ''845''], [''Si appoggia a'', ''838''], [''Si appoggia a'', ''839''], [''Si appoggia a'', ''848''], [''Tagliato da'', ''600''], [''Tagliato da'', ''616''], [''Tagliato da'', ''618''], [''Tagliato da'', ''620''], [''Tagliato da'', ''622'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '499', 'USM', 'Struttura con andamento NE/SO, individuata in prossimità del limite NO del Settore 2b, realizzata in laterizi, raramente integri e posto sia di testa che di lista, legati con malta mediamente tenace di colore giallastro, con inclusi millimetrici e centimetrici e posti in opera su filari orizzontali piuttosto regolari e quasi privi di inzeppature. Il muro si lega a S con US 498 e a N con 499 e si conserva per 12 corsi regolari, per un''altezza totale di 0.8 m, di dimensioni pari a 0.44 m di larghezza 2.10 m. Data la frammentarietà dei mattoni, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 7 cm, la lunghezza varia da 27 a 30 cm, mentre la larghezza da 12 a 14 cm. . Tra le tipologie costruttive documentate in corso di scavo, USM 499 è ascrivibile alla 1a', '1', '2', '[[''Coperto da'', ''292''], [''Copre'', ''754''], [''Gli si appoggia'', ''349''], [''Gli si appoggia'', ''510''], [''Gli si appoggia'', ''555''], [''Gli si appoggia'', ''568''], [''Gli si appoggia'', ''569''], [''Gli si appoggia'', ''570''], [''Gli si appoggia'', ''572''], [''Gli si appoggia'', ''574''], [''Gli si appoggia'', ''580''], [''Si appoggia a'', ''606''], [''Si appoggia a'', ''783''], [''Si lega a'', ''497''], [''Si lega a'', ''538''], [''Tagliato da'', ''794'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '497', 'USM', 'Struttura con andamento NE/SO, individuata in prossimità del limite NO del Settore 2b, realizzata in laterizi, raramente integri, legati con malta poco tenace di colore giallastro, con inclusi millimetrici e centimetrici e posti sia di testa che di lista su corsi orizzontali, quasi privi di inzeppature. Il muro si lega a S con US 498 e a N con 499 e si conserva per 12 corsi, per un''altezza totale di 1 m, di larghezza pari a 0.48 m di lunghezza 2.4 m. Data la frammentarietà dei mattoni, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 7 cm, la lunghezza varia da 27 a 30 cm, mentre la larghezza da 12 a 14 cm. Tra le tipologie documentate in corso di scavo, l''USM 497 è riferibile alla 1a', '1', '2', '[[''Coperto da'', ''492''], [''Copre'', ''756''], [''Gli si appoggia'', ''510''], [''Gli si appoggia'', ''552''], [''Gli si appoggia'', ''555''], [''Gli si appoggia'', ''567''], [''Gli si appoggia'', ''568''], [''Gli si appoggia'', ''569''], [''Gli si appoggia'', ''572''], [''Gli si appoggia'', ''574''], [''Gli si appoggia'', ''580''], [''Si appoggia a'', ''591''], [''Si lega a'', ''498''], [''Si lega a'', ''499''], [''Tagliato da'', ''505''], [''Tagliato da'', ''561'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '626', 'USM', 'Struttura muraria individuata nel Settore 2b, nella porzione NO, documentata inizialmente in pianta durante l''esecuzione del Saggio 13, successivamente anche in alzato durante la realizzazione del Saggio 16. Il muro ha un andamento semicircolare ed è realizzato in laterizi, raramente integri, anche in frammenti di dimensioni ridotte posti principalmente di lista e legati con abbondante malta piuttosto tenace, di colore biancastro con inclusi millimetrici e centimetrici. Si documentano in alzato tredici filari orizzontali regolari, con sporadiche inzeppature realizzate con frammenti di piccola misura, mentre in pianta si riconoscono due paramenti in mattoni e un sacco realizzato con abbondante malta e frammenti di dimensioni ridotte, di larghezza complessiva pari a circa 0.45 m. L''arco massimo della struttura misura 2 m, mentre l''altezza dei tredici corsi è di 0.92 m. Data la frammentarietà degli elementi costitutivi, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 6 cm, mentre le altre dimensioni non sono verificabili. Tra le tipologie costruttive documentate in corso di scavo, USM 626 è ascrivibile alla 1a', '2', '', '[[''Coperto da'', ''606''], [''Coperto da'', ''611''], [''Coperto da'', ''613''], [''Coperto da'', ''705''], [''Coperto da'', ''749''], [''Gli si appoggia'', ''706''], [''Gli si appoggia'', ''709''], [''Gli si appoggia'', ''748''], [''Gli si appoggia'', ''784''], [''Gli si appoggia'', ''785''], [''Gli si appoggia'', ''786''], [''Si lega a'', ''752''], [''Tagliato da'', ''548''], [''Tagliato da'', ''725''], [''Tagliato da'', ''790'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '723', 'US', 'Taglio in origine di forma subcircolare in pianta, di cui si documenta solo un breve tratto della parte NE, nel punto in cui esso intercetta la fornace da campana STR. 18. Alle quote di progetto l''evidenza non risultava visibile, perchè obliterata da una grande fossa di spoliazione e durante l''indagine presso la fornace è stata massa in luce solo parzialmente. Il diametro del taglio, individuato nel Settore 2b è pari a 2.5 m', '1', '3', '[[''Riempito da'', ''721''], [''Riempito da'', ''722''], [''Taglia'', ''233''], [''Taglia'', ''241''], [''Taglia'', ''242''], [''Taglia'', ''671''], [''Taglia'', ''672''], [''Taglia'', ''701''], [''Taglia'', ''712''], [''Taglia'', ''714''], [''Taglia'', ''715''], [''Taglia'', ''718''], [''Taglia'', ''726''], [''Taglia'', ''728''], [''Taglia'', ''729''], [''Taglia'', ''730''], [''Taglia'', ''733''], [''Taglia'', ''736''], [''Tagliato da'', ''674'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '858', 'US', 'Taglio di forma sub-rettangolare in pianta, con orientamento NE/SO, individuato nella porzione settentrionale del Settore 3, di fronte a S. Colomba. Esso non conserva i limiti originari in quanto risulta tagliata nella porzione SO dallo scavo dal passaggio della fogna e dallo scavo per la fibra ottica.', '2', '1', '[[''Riempito da'', ''856''], [''Riempito da'', ''857''], [''Riempito da'', ''859''], [''Riempito da'', ''860''], [''Riempito da'', ''861''], [''Riempito da'', ''863''], [''Riempito da'', ''864''], [''Riempito da'', ''865''], [''Riempito da'', ''866''], [''Riempito da'', ''867''], [''Riempito da'', ''868''], [''Riempito da'', ''869''], [''Riempito da'', ''870''], [''Riempito da'', ''871''], [''Taglia'', ''872''], [''Taglia'', ''97'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '548', 'US', 'Taglio di forma subcircolare, profilo e andamento regolari, con pareti oblique e fondo concavo, di diametro pari a 3 m e di profondità pari a circa 2 m, individuato nei pressi dell''angolo N del Settore 2b. La buca, interpretata da subito come evidenza moderna, è stata sfruttata per verificare lo stato di conservazione delle strutture individuate nel Saggio 13, in particolare il muro con andamento circolare US 626, che risulta da essa tagliato, assieme alla stratigrafia circostante', '3', '', '[[''Riempito da'', ''547''], [''Taglia'', ''292''], [''Taglia'', ''349''], [''Taglia'', ''491''], [''Taglia'', ''492''], [''Taglia'', ''549''], [''Taglia'', ''558''], [''Taglia'', ''559''], [''Taglia'', ''626''], [''Taglia'', ''703''], [''Taglia'', ''705''], [''Taglia'', ''706''], [''Taglia'', ''709''], [''Taglia'', ''710''], [''Taglia'', ''749''], [''Taglia'', ''750''], [''Taglia'', ''768''], [''Taglia'', ''790''], [''Taglia'', ''877'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '606', 'USM', 'Struttura con andamento NE/SO, individuata nella parte centrale del Settore 2b, nella porzione NO, realizzata in mattoni sia integri che frammentari, posti di principalmente di lista, ma presenti anche di testa, legati con malta tenace di colore giallastro, con i letti di posa rientranti rispetto al filo dei laterizi. Il muro si conserva per quindici filari orizzontali, piuttosto regolari, con sporadiche inzeppature realizzate con frammenti di piccole dimensioni, ed è costituito da due paramenti a vista e da un sacco realizzato con laterizi di pezzatura ridotta e da abbondante malta. Le sue dimensioni massima visibili in pianta sono pari a 0.48 m di larghezza e 0.97 m di lunghezza, mentre l''altezza massima documentata è di 1.3 m. Data la frammentarietà dei mattoni, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 7 cm, la lunghezza varia da 27 a 30 cm, mentre la larghezza da 12 a 14 cm. Tra le tipologie costruttive documentate in corso di scavo, USM 606 è ascrivibile alla 1b', '2', '', '[[''Coperto da'', ''492''], [''Coperto da'', ''538''], [''Copre'', ''626''], [''Copre'', ''775''], [''Gli si appoggia'', ''498''], [''Gli si appoggia'', ''499''], [''Gli si appoggia'', ''580''], [''Gli si appoggia'', ''604''], [''Gli si appoggia'', ''611''], [''Gli si appoggia'', ''612''], [''Gli si appoggia'', ''754''], [''Gli si appoggia'', ''782''], [''Si lega a'', ''613''], [''Tagliato da'', ''579'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '674', 'US', 'Taglio di forma subcircolare, individuato nel Settore 2b, di diametro pari a 2.7 m posto immediatamente a O rispetto alla fornace da campana STR. 18. L''evidenza è stata individuata in pianta e scavata unicamente nella porzione di intersezione con la struttura della fornace. La parete esposta presenta un andamento pressoché verticale mentre il fondo non è stato raggiunto.', '3', '3', '[[''Riempito da'', ''673''], [''Taglia'', ''241''], [''Taglia'', ''242''], [''Taglia'', ''671''], [''Taglia'', ''672''], [''Taglia'', ''701''], [''Taglia'', ''712''], [''Taglia'', ''714''], [''Taglia'', ''715''], [''Taglia'', ''718''], [''Taglia'', ''721''], [''Taglia'', ''722''], [''Taglia'', ''723''], [''Taglia'', ''726''], [''Taglia'', ''728''], [''Taglia'', ''729''], [''Taglia'', ''730''], [''Taglia'', ''733'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '456', 'US', 'Strato a matrice limosa con una ridotta componente di argilla, di colore marrone e consistenza poco compatta, con laterizi in frammenti, ciottoli fluviali e pietre di piccole e medie dimensioni e lenti di malta, individuato nel Settore 3 durante lo scavo della rete fognaria. Lo strato non conserva i limiti originari in quanto risulta tagliato da sottoservizi contemporanei oltre che da diverse sepolture (TB2, TB3, TB4, TB5, TB6, TB7, TB8, TB9, TB10, TB11)', '2', '', '[[''Coperto da'', ''97''], [''Tagliato da'', ''459''], [''Tagliato da'', ''460''], [''Tagliato da'', ''463''], [''Tagliato da'', ''467''], [''Tagliato da'', ''470''], [''Tagliato da'', ''472''], [''Tagliato da'', ''475''], [''Tagliato da'', ''478''], [''Tagliato da'', ''481''], [''Tagliato da'', ''484''], [''Tagliato da'', ''487''], [''Tagliato da'', ''526''], [''Tagliato da'', ''874'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '797', 'US', 'Struttura con andamento NE/SO, immediatamente a SO rispetto alla STR. 29, di cui segue l''orientamento. Essa non è visibile in pianta perchè coperta da un rifacimento più tardo (US 850) e in parte da una tamponatura in materiale di reimpiego (US 814). Durante l''indagine sono stati messi in luce due tratti del paramento SE durante lo scavo dei Saggi 20 e 21. Della struttura in alzato si conservano cinque filari orizzontali regolari, di altezza pari a circa 0.32 m, realizzati con laterizi in frammenti, soprattutto tegole, che presentano colorazioni variabili dal giallo all''arancio, al rosso, anche di dimensioni piuttosto ridotte, legati con argilla depurata di colore giallastro. L''ampliamento dell''area di scavo in direzione SO ha permesso di individuare l''angolo SO del muro ma la presenza della tamponature US 814 non rende visibile quello NE. Data la frammentarietà degli elementi costitutivi, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 6.5 cm, mentre le altre dimensioni non sono verificabili. Tra le tipologie costruttive documentate in corso di scavo, USM 797 è ascrivibile alla 5', '2', '2', '[[''Coperto da'', ''814''], [''Coperto da'', ''850''], [''Copre'', ''851''], [''Gli si appoggia'', ''567''], [''Gli si appoggia'', ''792''], [''Gli si appoggia'', ''830''], [''Gli si appoggia'', ''831''], [''Gli si appoggia'', ''832''], [''Gli si appoggia'', ''833''], [''Gli si appoggia'', ''836''], [''Gli si appoggia'', ''840''], [''Gli si appoggia'', ''845'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '590', 'US', 'Struttura con andamento ONO/ESE, individuata nella parte centrale del Settore 2b, nella porzione NO, realizzata in principalmente mattoni, anche in piccoli frammenti, posti principalmente di lista, e frammenti di tegole, legati con argilla depurata di colore giallo. Il muro presenta uno stato di conservazione non originario, tagliato da numerose buche e lacunoso sul limite O. Della struttura si documenta un tratto di misure pari a 0.65 m di larghezza massima e 2.5 m di lunghezza massima. Il muro non presenta una vera e propria fondazione ma sembra appoggiarsi su uno zoccolo di argilla depurata e sporadici frammenti laterizi', '1', '', '[[''Coperto da'', ''586''], [''Coperto da'', ''595''], [''Coperto da'', ''597''], [''Coperto da'', ''727''], [''Copre'', ''765''], [''Gli si appoggia'', ''581''], [''Gli si appoggia'', ''582''], [''Gli si appoggia'', ''720''], [''Tagliato da'', ''596''], [''Tagliato da'', ''603''], [''Tagliato da'', ''642''], [''Tagliato da'', ''703''], [''Tagliato da'', ''820'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '672', 'US', 'Riempimento costituito da carbone in frustoli di piccole e medie dimensioni e frammenti di bronzo di forma irregolare e misure variabili, in matrice limo sabbiosa di colore marrone e consistenza poco compatta, rinvenuto al di sopra dello stampo centrale della fornace STR. 18. Il deposito non conserva i limiti originari in quanto tagliato per la messa in opera della fossa da grano STR. 19 e dal relativo taglio di spoliazione. La potenza massima documentata è pari a 0.3 m. In corso di scavo è stato recuperato un campione di carbone (C11_RA 475)', '1', '', '[[''Coperto da'', ''671''], [''Coperto da'', ''691''], [''Coperto da'', ''701''], [''Coperto da'', ''711''], [''Copre'', ''714''], [''Copre'', ''715''], [''Copre'', ''716''], [''Copre'', ''717''], [''Copre'', ''718''], [''Copre'', ''726''], [''Copre'', ''728''], [''Riempie'', ''241''], [''Si appoggia a'', ''734''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '591', 'US', 'Fusto di colonna scanalata in pietra calcarea, individuato presso l''angolo S della STR. 15, non inglobato all''interno dei perimetrali dell''ambiente, i quali si appoggiano all''elemento lapideo preesistente. Del fusto, di circonferenza pari a 0.33 m, è stata messa in luce solo la parte sommitale, per un''altezza di circa 1.1 m, scavando statigraficamente gli strati che gli andavano in appoggio, ma senza verificare il livello su cui essa si imposta.', '2', '', '[[''Coperto da'', ''492''], [''Gli si appoggia'', ''497''], [''Gli si appoggia'', ''498''], [''Gli si appoggia'', ''566''], [''Gli si appoggia'', ''567''], [''Gli si appoggia'', ''709''], [''Gli si appoggia'', ''758''], [''Gli si appoggia'', ''771''], [''Gli si appoggia'', ''817''], [''Gli si appoggia'', ''835''], [''Gli si appoggia'', ''841'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '100', 'US', 'Taglio rettilineo con andamento regolare, individuato in pianta ma non indagato in sezione in quanto relativo ad una canaletta. In corso di scavo è stato documentato un tratto pari a 12.4 m con andamento NO/SE e due tratti secondari con andamento N/S, pari complessivamente a 8.4 m. La larghezza del taglio varia tra 0.7 a 0.9 m', '3', '2', '[[''Riempito da'', ''186''], [''Riempito da'', ''98''], [''Riempito da'', ''99''], [''Taglia'', ''116''], [''Taglia'', ''119''], [''Taglia'', ''233''], [''Taglia'', ''294''], [''Taglia'', ''52''], [''Taglia'', ''630''], [''Taglia'', ''631''], [''Taglia'', ''632''], [''Taglia'', ''738''], [''Taglia'', ''739''], [''Taglia'', ''97''], [''Tagliato da'', ''732'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '790', 'US', 'Taglio individuato in sezione nel Settore 2b, a seguito dell''asportazione del riempimento della buca US 548, presso la parete O della stessa. L''evidenza non è stata individuata in pianta in quanto coperta da altri livelli, mentre mostra un profilo regolare in sezione, pareti oblique e fondo concavo, di diametro massimo pari a 1.6 e profondità massima di 1.38 m. L''evidenza è stata scavata a mezzo meccanico, senza rispettarne i limiti originari', '1', '', '[[''Riempito da'', ''710''], [''Taglia'', ''613''], [''Taglia'', ''626''], [''Taglia'', ''704''], [''Taglia'', ''705''], [''Taglia'', ''706''], [''Taglia'', ''746''], [''Taglia'', ''748''], [''Taglia'', ''784''], [''Taglia'', ''785''], [''Taglia'', ''786''], [''Taglia'', ''787''], [''Taglia'', ''788''], [''Tagliato da'', ''548''], [''Tagliato da'', ''703'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '583', 'US', 'Struttura con andamento ONO/ESE, individuata nella parte centrale del Settore 2b, nella porzione NO, realizzata in principalmente mattoni, raramente integri, posti principalmente di lista, e frammenti di tegole, legati con argilla depurata di colore giallo. Il muro presenta uno stato di conservazione non originario, tagliato da numerose buche. Si documenta un tratto di misure pari a 0.45 m di larghezza massima e 4 m di lunghezza massima', '1', '1', '[[''Coperto da'', ''492''], [''Coperto da'', ''770''], [''Copre'', ''763''], [''Gli si appoggia'', ''566''], [''Gli si appoggia'', ''581''], [''Gli si appoggia'', ''582''], [''Gli si appoggia'', ''720''], [''Gli si appoggia'', ''761''], [''Tagliato da'', ''594''], [''Tagliato da'', ''650''], [''Tagliato da'', ''703''], [''Tagliato da'', ''777'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '296', 'US', 'Struttura con andamento NO/SE, individuata nei settori 2c e 4, presso il limite meridionale dell''area di scavo, costituita da ciottoli fluviali di piccole e medie dimensioni, legati con abbondante malta grigiastra molto tenace. Il muro si lega a NO con US 293 e 678, mentre nel limite SE risulta tagliato da sottoservizi contemporanei. La sua lunghezza è pari a 15.7 e la larghezza media è di 1.45', '2', '1', '[[''Coperto da'', ''168''], [''Gli si appoggia'', ''208''], [''Gli si appoggia'', ''209''], [''Gli si appoggia'', ''210''], [''Gli si appoggia'', ''464''], [''Riempie'', ''742''], [''Si lega a'', ''293''], [''Si lega a'', ''678''], [''Tagliato da'', ''172''], [''Tagliato da'', ''262''], [''Tagliato da'', ''682''], [''Uguale a'', ''263'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '351', 'US', 'Taglio di forma piuttosto irregolare, con andamento subcircolare con limiti frastagliati ma ben distinguibili, profilo regolari, con pareti quasi verticali e fondo piatto, individuato nel Settore 2 presso l''angolo esterno E dell''abitazione basso medievale CAS-1', '2', '', '[[''Riempito da'', ''350''], [''Taglia'', ''15''], [''Taglia'', ''250''], [''Taglia'', ''266''], [''Taglia'', ''267''], [''Taglia'', ''284''], [''Taglia'', ''341''], [''Taglia'', ''374''], [''Taglia'', ''381''], [''Taglia'', ''382''], [''Taglia'', ''387''], [''Taglia'', ''431''], [''Taglia'', ''436''], [''Taglia'', ''437''], [''Taglia'', ''438'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '566', 'US', 'Strato di laterizi in frammenti di diverse dimensioni, principalmente tegole, pietre di medie e piccola misura, in matrice limo argillosa di colore marrone chiaro e consistenza compatta, con malta sciolta e in grumi. Lo strato presenta andamento tabulare e una potenza media pari a 0.2 m ed è stato individuato immediatamente a SE rispetto alla STR. 15.Lo scavo ha restituito fauna, sporadici frammenti di vetro e metallo, tra cui due monete in bronzo di età bizantina (RA 386, 387), e una certa quantità di frammenti ceramici databili genericamente all''età tardo romana', '1', '', '[[''Coperto da'', ''492''], [''Copre'', ''567''], [''Copre'', ''587''], [''Copre'', ''773''], [''Copre'', ''792''], [''Si appoggia a'', ''583''], [''Si appoggia a'', ''591''], [''Tagliato da'', ''496''], [''Tagliato da'', ''502''], [''Tagliato da'', ''509''], [''Tagliato da'', ''553''], [''Tagliato da'', ''561''], [''Uguale a'', ''771'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '153', 'US', 'Strato costitutito da laterizi sbricciolati e pressati, con malta sciolta e in grumi, ghiaia in dispersione e ciottoli di piccole dimensioni, di colore rosato e consistenza molto compatta, individuata nella parte dell''area di scavo a SO rispetto al teatro Galli. Lo spessore del deposito è pari a circa 0.1 m', '3', '', '[[''Coperto da'', ''1''], [''Copre'', ''145''], [''Copre'', ''148''], [''Copre'', ''149''], [''Copre'', ''150''], [''Copre'', ''151''], [''Copre'', ''152''], [''Copre'', ''161''], [''Copre'', ''164''], [''Copre'', ''226''], [''Copre'', ''232''], [''Copre'', ''665''], [''Copre'', ''692''], [''Tagliato da'', ''163''], [''Tagliato da'', ''214'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '613', 'USM', 'Struttura con andamento NO/SE, individuata nella parte centrale del Settore 2b, presso il limite  NO, realizzata in mattoni sia integri che frammentari, posti di principalmente di lista, ma presenti anche di testa, legati con malta tenace di colore giallastro. Il muro si conserva per otto corsi regolari, ed è costituito da due paramenti a vista e da un sacco realizzato con laterizi di pezzatura ridotta e da abbondante malta. Le sue dimensioni visibili in pianta sono pari a 0.50 m di larghezza massima, 1.8 m di lunghezza massima, 0.68 m di altezza massima e 0.5 m di altezza media. Il muro prosegue oltre il limite di scavo NO e non mantiene i limiti originari, tagliato per la realizzazione della STR. 20. Data la frammentarietà dei mattoni, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 7 cm, la lunghezza varia da 27 a 30 cm, mentre la larghezza da 12 a 14 cm. Tra le tipologie costruttive documentate in corso di scavo, USM 613 è ascrivibile alla 1a', '2', '2', '[[''Coperto da'', ''492''], [''Copre'', ''626''], [''Copre'', ''748''], [''Copre'', ''775''], [''Copre'', ''786''], [''Gli si appoggia'', ''612''], [''Si lega a'', ''606''], [''Si lega a'', ''746''], [''Si lega a'', ''747''], [''Tagliato da'', ''625''], [''Tagliato da'', ''703''], [''Tagliato da'', ''790''], [''Tagliato da'', ''823'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '52', 'US', 'Strato individuato in sezione nel Settore 2, all’interno del Saggio 3 e asportato a mezzo meccanico. Esso presenta un andamento tabulare, con lo spessore di qualche cm, matrice limo-sabbiosa di colore marrone chiaro e consistenza molto compatta ed è caratterizzato da frammenti di laterizi di piccole dimensioni', '3', '2', '[[''Coperto da'', ''2''], [''Copre'', ''30''], [''Copre'', ''34''], [''Copre'', ''35''], [''Copre'', ''36''], [''Copre'', ''38''], [''Copre'', ''40''], [''Copre'', ''42''], [''Copre'', ''44''], [''Copre'', ''50''], [''Copre'', ''51''], [''Copre'', ''55''], [''Copre'', ''57''], [''Copre'', ''70''], [''Copre'', ''72''], [''Tagliato da'', ''33'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '709', 'US', 'Strato a matrice argillo sabbiosa di colore marrone e consistenza compatta con malta sciolta e in grumi, laterizi in frammenti, sporadiche pietre di piccole dimensioni, con andamento tabulare e potenza massima documentata pari a 0.5 m, individuato nel Settore 2b, in sezione durante lo scavo del Saggio 16 e successivamente in pianta a seguito dell''asportazione dello strato US 567. Lo scavo ha restituito sporadici elementi in metallo, e una certa quantità di frammenti ceramici, tra cui due frammenti di LRA 3 e LRA 4, frammenti di anfore egee e frammenti di imitazione di sigillata africana, databili al pieno V sec. d.C. ', '1', '', '[[''Coperto da'', ''567''], [''Coperto da'', ''705''], [''Coperto da'', ''816''], [''Coperto da'', ''840''], [''Copre'', ''835''], [''Si appoggia a'', ''591''], [''Si appoggia a'', ''626''], [''Tagliato da'', ''548''], [''Tagliato da'', ''708''], [''Tagliato da'', ''725''], [''Tagliato da'', ''755''], [''Tagliato da'', ''834'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '3', 'US', 'Strato di argilla e sabbia di consistenza compatta e colore grigio scuro, caratterizzato dalla presenza di laterizi, ciottoli, pietre e malta sciolta e frammenti fittili. Lo strato è presente nei Settori 1 e 2, al di sotto della pavimentazione in ciottoli US 2', '3', '2', '[[''Copre'', ''84''], [''Coperto da'', ''2''], [''Copre'', ''10''], [''Copre'', ''20''], [''Copre'', ''4''], [''Copre'', ''7''], [''Copre'', ''83''], [''Copre'', ''85''], [''Copre'', ''89''], [''Copre'', ''9''], [''Copre'', ''90''], [''Copre'', ''92''], [''Tagliato da'', ''102''], [''Tagliato da'', ''103''], [''Tagliato da'', ''88'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '21', 'US', 'Struttura voltata a botte, con andamento NE/SO, costituita da un unico filare di laterizi interi posti di taglio e legati con malta molto tenace di colore grigiastro, che costituisce la parte interna della copertura del condotto idrico ottocentesco. L''evidenza risulta visibile in pianta alle quote di sbancamento presso i Settori 1 e 2, in alcuni tratti in cui esse emerge dalla copertura esterna realizzata con ciottoli e frammenti laterizi legati con abbondante malta grigia di consistenza tenace (US 9). La struttura presenta internamente un rivestimento di intocaco di colore bianco, documentato durante l''ispezione del condotto realizzata da adArte nel Febbraio 2020. Nel tratto individuato la largezza massima della volta è pari a 1.18 m e la sua altezza, partendo dalla testa delle spallette è di 0.53 m', '3', '', '[[''Coperto da'', ''79''], [''Coperto da'', ''9''], [''Gli si appoggia'', ''24''], [''Gli si appoggia'', ''25''], [''Si lega a'', ''22''], [''Si lega a'', ''23''], [''Si lega a'', ''80''], [''Si lega a'', ''81''], [''Tagliato da'', ''19''], [''Tagliato da'', ''93''], [''Tagliato da'', ''94''], [''Tagliato da'', ''96'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '436', 'US', 'Strato a matrice limosa con una ridotta componente di argilla, di colore marrone e consistenza poco compatta, con laterizi in frammenti, ciottoli fluviali e pietre di piccole e medie dimensioni e lenti di malta, sia sciolta che in grumi, individuato nel Settore 2, nello spazio, presumibilmente aperto e non occupato da edifici, compreso tra le STR. 11, 26, 62 e 63. Lo scavo ha restituito numerosi reperti, tra cui alcune monete, due delle quali databili rispettivamente al XIV e alla seconda metà del XIII (RA 74, 75), altri elementi in metallo e frammenti ceramici, databili complessivamente ad un ampio arco temporale, che va dal VII al XVII secolo d.C.', '1', '', '[[''Copre'', ''15''], [''Tagliato da'', ''286''], [''Tagliato da'', ''351''], [''Tagliato da'', ''365''], [''Tagliato da'', ''369''], [''Tagliato da'', ''371''], [''Tagliato da'', ''373''], [''Tagliato da'', ''438''], [''Tagliato da'', ''490''], [''Uguale a'', ''250''], [''Uguale a'', ''397''], [''Uguale a'', ''451'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '594', 'US', 'Taglio di forma subcircolare, con profilo e andamento regolari, pareti oblique e fondo concavo, individuato nella porzione settentrionale del Settore 2b e di cui è stata scavata solo la metà NO. Il diametro del taglio è di 2.6 m, mentre la sua potenza massima è di 1.3 m. La buca ha tagliato la parte E della STR. 16, ed è stata intercettata a sua volta dalla spoliazione US 576', '1', '', '[[''Riempito da'', ''593''], [''Taglia'', ''581''], [''Taglia'', ''582''], [''Taglia'', ''583''], [''Taglia'', ''584''], [''Taglia'', ''761''], [''Taglia'', ''762''], [''Taglia'', ''763''], [''Taglia'', ''764''], [''Taglia'', ''772''], [''Taglia'', ''792''], [''Taglia'', ''833''], [''Taglia'', ''834''], [''Taglia'', ''853'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '2', 'US', 'Strato di ciottoli di dimensioni decimetrica, posti di piatto su un substrato sabbioso di colore marrone chiaro molto friabile. Strato di ciottoli di dimensioni decimetrica, posti di piatto su un substrato sabbioso di colore marrone chiaro molto friabile, rinvenuto su buona parte della superficie dell''area 3, soprattutto nei settori 1 e 2', '2', '1', '[[''Copre'', ''141''], [''Copre'', ''142''], [''Copre'', ''140''], [''Coperto da'', ''1''], [''Copre'', ''127''], [''Copre'', ''17''], [''Copre'', ''3''], [''Copre'', ''31''], [''Copre'', ''32''], [''Copre'', ''52''], [''Copre'', ''68''], [''Copre'', ''69''], [''Copre'', ''7''], [''Copre'', ''87''], [''Si appoggia a'', ''136'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '574', 'US', 'Riempimento a matrice limo sabbiosa di colore marrone e consistenza molto friabile, con sporadici frammenti laterizi di piccole e medie dimensioni, di potenza massima di 0.4, individuato nel Settore 2b, al di sotto della pavimentazione del vano TER-1. I limiti del deposito corrispondono ai limiti interno dell''ambiente', '2', '', '[[''Coperto da'', ''568''], [''Coperto da'', ''592''], [''Copre'', ''572''], [''Riempie'', ''755''], [''Si appoggia a'', ''497''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''499''], [''Si appoggia a'', ''570''], [''Si appoggia a'', ''571''], [''Si appoggia a'', ''782''], [''Si appoggia a'', ''789'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '734', 'US', 'Struttura con andamento leggermente ricurvo, costituita da un solo filare di pietre calcaree appena sbozzate, molto rubefatte e messe in opera in maniera disordinata, legate con argilla frammista a malta concotta. Della struttura, individuata nel Settore 2b, sul lato NE della fornace da campana STR. 18 e realizzata contro terra, si sono conservati dieci corsi, per un''altezza complessiva di 0.68 m. Essa non conserva i limiti originari in quanto è stata tagliata dalla fossa di fondazione della STR. 19 e dalla relativa buca di spoliazione', '1', '', '[[''Coperto da'', ''242''], [''Gli si appoggia'', ''671''], [''Gli si appoggia'', ''672''], [''Gli si appoggia'', ''701''], [''Gli si appoggia'', ''726''], [''Gli si appoggia'', ''728''], [''Gli si appoggia'', ''729''], [''Gli si appoggia'', ''730''], [''Riempie'', ''241''], [''Si lega a'', ''733'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '725', 'US', 'Taglio di buca individuata in sezione durante la realizzazione del Saggio 16, presso la parete NO dello stesso, il cui fondo è stato successivamente messo in luce in pianta,  presenta  profilo regolare, pareti oblique e fondo concavo ', '1', '', '[[''Riempito da'', ''724''], [''Taglia'', ''595''], [''Taglia'', ''611''], [''Taglia'', ''612''], [''Taglia'', ''626''], [''Taglia'', ''709''], [''Taglia'', ''737''], [''Taglia'', ''746''], [''Taglia'', ''747''], [''Taglia'', ''749''], [''Taglia'', ''750''], [''Taglia'', ''752''], [''Tagliato da'', ''703'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '582', 'US', 'Strato a matrice limosa di colore marrone chiaro e consistenza friabile, con un''alta percentuale di calce rosata a granulometria molto fine, lenti di cenere, frustoli di carbone e frammenti laterizi di piccole dimensioni, individuato nella porzione settentrionale del Settore 2b, all''interno della STR. 16 e ugualiato a US 698, non presente su tutta la superficie dell''ambiente, ma concentrato nella parte centrale. Il deposito mostra andamento irregolare e una potenza che varia da pochi cm a circa 0.18 m', '1', '', '[[''Coperto da'', ''581''], [''Coperto da'', ''584''], [''Copre'', ''720''], [''Si appoggia a'', ''583''], [''Si appoggia a'', ''590''], [''Tagliato da'', ''594''], [''Tagliato da'', ''634''], [''Tagliato da'', ''644''], [''Tagliato da'', ''646''], [''Tagliato da'', ''777''], [''Uguale a'', ''698'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '581', 'US', 'Strato eterogeneo, a matrice prevalentemente limosa di colore marrone chiaro e consistenza friabile, con frustoli di carbone e frammenti laterizi di dimensioni centimetriche e decimetriche, individuato nella porzione settentrionale del Settore 2b, all''interno della STR. 16', '1', '1', '[[''Coperto da'', ''492''], [''Copre'', ''582''], [''Copre'', ''584''], [''Si appoggia a'', ''583''], [''Si appoggia a'', ''590''], [''Tagliato da'', ''594''], [''Tagliato da'', ''634''], [''Tagliato da'', ''636''], [''Tagliato da'', ''638''], [''Tagliato da'', ''640''], [''Tagliato da'', ''648'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '733', 'US', 'Struttura con andamento leggermente ricurvo, costituita da un solo filare di pietre calcaree appena sbozzate, molto rubefatte e messe in opera in maniera disordinata, legate con argilla frammista a malta concotta. Della struttura, individuata nel Settore 2b, sul lato NO della fornace da campana STR. 18 e realizzata contro terra, si sono conservati tredici corsi, per un''altezza complessiva di 0.75 m. Essa non conserva i limiti originari in quanto è stata tagliata dalla fossa di fondazione della STR. 19 e dalla relativa buca di spoliazione', '1', '', '[[''Coperto da'', ''242''], [''Gli si appoggia'', ''691''], [''Gli si appoggia'', ''701''], [''Gli si appoggia'', ''728''], [''Gli si appoggia'', ''729''], [''Gli si appoggia'', ''730''], [''Riempie'', ''241''], [''Si lega a'', ''734''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '1', 'US', 'Strato di asfalto contemporaneo con un sottofondo costituito da conglomerato molto compatto di colore grigio chiaro. Rinvenuto nell''intera area indagata di Piazza Malatesta', '1', '1', '[[''Copre'', ''116''], [''Copre'', ''119''], [''Copre'', ''120''], [''Copre'', ''153''], [''Copre'', ''162''], [''Copre'', ''2''], [''Copre'', ''213''], [''Copre'', ''3''], [''Copre'', ''452''], [''Copre'', ''501''], [''Copre'', ''51''], [''Copre'', ''731''], [''Copre'', ''824''], [''Tagliato da'', ''272'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '538', 'USM', 'Struttura con andamento NE/SO, individuata nella parte centrale del Settore 2b, nella porzione NO, realizzata in principalmente mattoni di diversi moduli, posti principalmente di lista, frammenti di tegole e due pietre di piccole dimensioni, legati con argilla depurata di colore giallo. Il muro si conserva per nove filari, che mostrano segni di collassamento verso l''interno della STR. 15 ed è costituito da due filari irregolari e non ben distinguibili. Le sue dimensioni sono pari a 0.35 m di larghezza massima, 0.57 m di lunghezza massima e 0.7 m di altezza. Tra le tipologie costruttive documentate in corso di scavo, USM 538 è ascrivibile alla 4', '1', '2', '[[''Coperto da'', ''292''], [''Copre'', ''606''], [''Gli si appoggia'', ''349''], [''Gli si appoggia'', ''510''], [''Gli si appoggia'', ''555''], [''Gli si appoggia'', ''568''], [''Gli si appoggia'', ''569''], [''Gli si appoggia'', ''612''], [''Si lega a'', ''499''], [''Si lega a'', ''592'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '500', 'USM', 'Struttura con andamento NE/SO, individuata nella parte centrale del Settore 2b, nella porzione NO, realizzata in principalmente mattoni, integri o in frammenti di misura maggiore presso il limite N, posti di lista, in pezzatura minore nella resto della muratura, legati con argilla depurata di colore giallo. Il muro si conserva per otto corsi, che mostrano segni di collassamento verso l''interno della STR. 15 ed è costituito da due filari irregolari e non ben distinguibili. Le sue dimensioni sono pari a 0.38 m di larghezza massima, 0.44 m di lunghezza massima e 0.6 m di altezza. Tra le tipologie costruttive documentate in corso di scavo, USM 500 è ascrivibile alla 4', '1', '2', '[[''Coperto da'', ''292''], [''Copre'', ''789''], [''Gli si appoggia'', ''349''], [''Gli si appoggia'', ''510''], [''Gli si appoggia'', ''555''], [''Gli si appoggia'', ''568''], [''Gli si appoggia'', ''569''], [''Si lega a'', ''498''], [''Si lega a'', ''592''], [''Si lega a'', ''783'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '441', 'US', 'Strato a matrice limosa con una ridotta componente di argilla, di colore marrone e consistenza poco compatta, con laterizi in frammenti, ciottoli fluviali e pietre di piccole e medie dimensioni e lenti di malta, sia sciolta che in grumi, individuato nel Settore 2, all''interno della STR. 11, a seguito dell''asportazione dello strato di macerie US 397. Durante la pulizia superficiale dello strato sono state rinvenute 4 monete in bronzo (RA 392, 393, 394, 395), risultate momentaneamente illeggibili, ma che, a giudicare dalle dimensioni e dalla tipologia, sono genericamente databili ai secoli basso medievali', '1', '2', '[[''Coperto da'', ''270''], [''Coperto da'', ''397''], [''Coperto da'', ''532''], [''Coperto da'', ''534''], [''Copre'', ''15''], [''Copre'', ''398''], [''Tagliato da'', ''274''], [''Tagliato da'', ''276''], [''Tagliato da'', ''445''], [''Tagliato da'', ''446''], [''Tagliato da'', ''453'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '2', '5', 'US', 'Porzione E del taglio poligonale di grandissime dimensioni, occupato dal fossato di Castel Sismondo. Le pareti del taglio sono occupate dalla controscarpa del fossato, pertanto non risultano visibili. Osservando l''andamento del muro costruito contro terra è possibile constatare come esse seguano un andamento obliquo, con una pendenza di circa 60° partendo dalla linea del piano di calpestio', '1', '2', '[[''Riempito da'', ''2''], [''Riempito da'', ''23''], [''Riempito da'', ''29''], [''Riempito da'', ''3''], [''Riempito da'', ''31''], [''Riempito da'', ''32''], [''Riempito da'', ''4''], [''Taglia'', ''18''], [''Taglia'', ''19''], [''Taglia'', ''22''], [''Taglia'', ''24''], [''Taglia'', ''7'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '354', 'US', 'Strato di ghiaia e ciottoli di piccole dimensioni piuttosto compatta, in matrice argillosa di colore marrone chiaro, con andamento tabulare, individuato in maniera omogene, con qualche lacuna, all''interno della STR. 26', '2', '1', '[[''Coperto da'', ''355''], [''Coperto da'', ''412''], [''Tagliato da'', ''353''], [''Tagliato da'', ''359''], [''Tagliato da'', ''361''], [''Tagliato da'', ''367''], [''Tagliato da'', ''384''], [''Tagliato da'', ''386''], [''Tagliato da'', ''416''], [''Tagliato da'', ''608'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '568', 'US', 'Piano realizzato con un solo livello di bipedali dello spessore di 6-7 cm, legati con malta tenace rosata, documentato nel Settore 2b all''interno del vano TER-1, sospeso su suspensurae e coperto da uno strato di malta idraulica. La porzione SE del piano è stata asportata tramite mezzo meccanico', '1', '', '[[''Coperto da'', ''555''], [''Copre'', ''570''], [''Copre'', ''571''], [''Copre'', ''574''], [''Gli si appoggia'', ''569''], [''Si appoggia a'', ''497''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''499''], [''Si appoggia a'', ''500''], [''Si appoggia a'', ''538'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '712', 'US', 'Taglio in origine di forma subcircolare, individuato in pianta nel Settore 2b, al centro della fornae da campana STR. 18, e non ulteriormente indagato. Esso non conserva i limiti originari in quanto tagliato dalla fossa da grano STR. 19 e dalla relativa fossa di spoliazione. Il suo diametro è pari a 1.16 m ', '1', '', '[[''Riempito da'', ''714''], [''Riempito da'', ''715''], [''Riempito da'', ''716''], [''Riempito da'', ''717''], [''Riempito da'', ''718''], [''Riempito da'', ''736''], [''Si lega a'', ''241''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723''], [''Uguale a'', ''241'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '526', 'US', 'Taglio di forma sub rettangolare, individuato nel Settore 3, durante la realizzazione della nuova fogna, già intercettato dallo scavo per la messa in opera del gas, realizzato per la costruzione della cassa in muratura della sepoltura multipla TB 15. La porzione conservata del taglio presenta misure pari a 1.75 x 0.7, con una profondità di 0.9 m', '2', '1', '[[''Riempito da'', ''522''], [''Riempito da'', ''524''], [''Riempito da'', ''525''], [''Riempito da'', ''530''], [''Riempito da'', ''531''], [''Riempito da'', ''536''], [''Riempito da'', ''537''], [''Riempito da'', ''541''], [''Riempito da'', ''542''], [''Taglia'', ''456'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '510', 'US', 'Riempimento a matrice limo sabbiosa di colore marrone e consistenza friabile, con malta sciolta e in grumi, con sporadici frammenti laterizi, pietre e ciottoli fluviali di piccole e medie dimensioni, individuato nel Settore 2b, presso il limite NO dello stesso, all''interno del vano TER-1. Il deposito conserva i limiti originari, presenta andamento tabulare e una potenza di circa 0.5 m. Lo scavo ha restituito un nummo in bronzo illeggibile', '2', '', '[[''Coperto da'', ''292''], [''Copre'', ''555''], [''Copre'', ''569''], [''Si appoggia a'', ''497''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''499''], [''Si appoggia a'', ''500''], [''Si appoggia a'', ''538''], [''Tagliato da'', ''505''], [''Uguale a'', ''573'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '349', 'US', 'Strato costituito da calce di colore rossastro e consistenza compatta, con ghiaia, frammenti laterizi e ciottoli di piccole dimensioni, individuato nei Settori 2, 2b, 3 e 5, lungo un''area con andamento NE/SO, di larghezza pari a circa 6.5 m e documentata in pianta per una lunghezza di circa 45 m. Lo spesso dello strato è pari a circa 0.1 m. Dell''evidenza, che è stata tagliata sul limite NO da un sottoservizio contemporanea, è stato messo in luce il limite SE per la lunghezza sopra citata, mentre quello NO è stato verificato mediante lo scavo di due trincee, funzionali alla determinazione della larghezza del deposito', '2', '1', '[[''Coperto da'', ''292''], [''Copre'', ''549''], [''Copre'', ''573''], [''Riempie'', ''703''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''499''], [''Si appoggia a'', ''500''], [''Si appoggia a'', ''538''], [''Tagliato da'', ''513''], [''Tagliato da'', ''548'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '76', 'US', 'Taglio individuato in pianta e non indagato in profondità. La sua forma segue quella della struttura per cui è stato realizzato. Esso risulta quindi di forma  irregolare, piuttosto articolata, costituita da due segmenti rettilinei con andamento N/S ed E/O, che formano internamente un angolo retto, il quale, esternamente si risolve in un tratto obliquo. ', '3', '2', '[[''Riempito da'', ''73''], [''Riempito da'', ''74''], [''Riempito da'', ''75''], [''Riempito da'', ''81''], [''Taglia'', ''233''], [''Taglia'', ''52''], [''Taglia'', ''53''], [''Taglia'', ''56''], [''Taglia'', ''85''], [''Tagliato da'', ''47''], [''Tagliato da'', ''732'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '728', 'US', 'Riempiemento a matrice limosa di colore marrone e consistenza poco compatta, a tessitura fine, con concotto, piccoli frammenti di laterizi in dispersione e frustoli di carbone, individuate nel Settore 2b, all''interno della fornace da campana STR. 18. Il deposito, di potenza pari a circa 0.2 m, non conserva i limiti originari in quanto è stato tagliato dalla fossa da grano STR. 19 e dalla relativa fossa di spoliazione', '1', '', '[[''Coperto da'', ''672''], [''Coperto da'', ''701''], [''Copre'', ''729''], [''Copre'', ''730''], [''Riempie'', ''241''], [''Si appoggia a'', ''714''], [''Si appoggia a'', ''733''], [''Si appoggia a'', ''734''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '396', 'US', 'Taglio di forma rettilinea, con andamento NE/SO, individuato nel Settore 2, presso il limite NO, in corrispondenza di quello che doveva essere il muro perimetrale che chiudeva la STR. 26 a NO. Il taglio misura 8.4 x 1.1 m, con una una profondità media di 0.8 m e presenta le pareti verticali e il fondo piatto', '2', '', '[[''Riempito da'', ''380''], [''Riempito da'', ''394''], [''Taglia'', ''15''], [''Taglia'', ''250''], [''Taglia'', ''381''], [''Taglia'', ''382''], [''Taglia'', ''433''], [''Taglia'', ''607''], [''Taglia'', ''608''], [''Tagliato da'', ''395''], [''Tagliato da'', ''78'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '561', 'US', 'Taglio di forma sub rettangolare, individuata nella porzione settentrionale del Settore 2b, immediatamente a S rispetto all''angolo S della STR. 15. L''evidenza presenta profilo e andamento regolari, con pareti oblique e fondo leggermente concavo. Le dimensioni dell''evidenza sono pari a 1.6 x 0.5 m, con una profondità pari a 0.3 m', '1', '2', '[[''Riempito da'', ''560''], [''Riempito da'', ''562''], [''Riempito da'', ''563''], [''Taglia'', ''492''], [''Taglia'', ''497''], [''Taglia'', ''498''], [''Taglia'', ''566''], [''Taglia'', ''567''], [''Taglia'', ''587''], [''Taglia'', ''771''], [''Taglia'', ''817'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '714', 'US', 'Struttura in argilla concottata e laterizi, individuata nel Settore 2b nella parte centrale della fornace STR. 18, costituita da un filare in laterizi che vanno a formare un cordolo di sostegno con andamento circolare, da cui parte uno strato di argilla concottata che, si sviluppa in verticale fino al raggiungimento della quota del piano di appoggio centrale della fornace. La struttura non conserva i limiti originari in quanto tagliata dalla fossa da grano STR. 19 e dalla relativa fossa di spoliazione. Il suo diametro misura 1.16 m e l''altezza massima conservata della parete di concotto è di 0.18 m ', '1', '', '[[''Coperto da'', ''672''], [''Gli si appoggia'', ''717''], [''Gli si appoggia'', ''728''], [''Gli si appoggia'', ''729''], [''Gli si appoggia'', ''730''], [''Riempie'', ''241''], [''Riempie'', ''712''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '2', '7', 'US', 'Strato costiuito principalmente da malta sciolta e in grumi, di colore rosato e consistenza friabile, compposta da sabbia  a grossa granulometria e una bassa percntuale di calce. Nello strato sono presenti laterizi in frammenti e ciottoli di piccole e medie dimensioni.  Il livello è stato individuato in estensione su tutta la superficie del Settore 2 del Lotto 2 non occupata da strutture, con andamento tabulare e uno spessore pari a circa 0,4 m. Esso non conserva i limiti originari  in quanto tagliato da diverse azioni successive e non ha restituito materiale datante', '1', '1', '[[''Coperto da'', ''22''], [''Coperto da'', ''6''], [''Copre'', ''24''], [''Tagliato da'', ''10''], [''Tagliato da'', ''13''], [''Tagliato da'', ''15''], [''Tagliato da'', ''17''], [''Tagliato da'', ''19''], [''Tagliato da'', ''21''], [''Tagliato da'', ''5'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '302', 'US', 'Riempimento a matrice sabbiosa di colore marrone chiaro e consistenza friabile, con numerosi frammenti laterizi, ciottoli fluviali di medie e piccole dimensioni, pietre e malta sia sciolta che in grumi, individuato nel Settore 4, all''interno del butto strutturale BUT-2, e in parte asportato manualmente; in seguito, per ragioni di sicurezza, la rimozione è proseguita tramite mezzo meccanico, senza raggiungere il fondo. Lo scavo ha restituito una moneta databile al XIV secolo ', '1', '1', '[[''Coperto da'', ''232''], [''Copre'', ''402''], [''Riempie'', ''264''], [''Si appoggia a'', ''144''], [''Si appoggia a'', ''301''], [''Si appoggia a'', ''403''], [''Si appoggia a'', ''404''], [''Si appoggia a'', ''449''], [''Si appoggia a'', ''450'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '771', 'US', 'Strato di laterizi in frammenti di diverse dimensioni, principalmente tegole, pietre di medie e piccola misura, in matrice limo argillosa di colore marrone chiaro e consistenza compatta, con malta sciolta e in grumi, individuato nella porzione NO del Settore 2b. Lo strato presenta andamento tabulare e una potenza media pari a 0.2 m ed è stato individuato immediatamente a SO rispetto al vano TER-1. Lo scavo ha restituito fauna, sporadici frammenti di vetro e metallo, tra cui due nummi in bronzo (RA 404), e numerosi frammenti ceramici che, ad una prima analisi, datano il contesto al VI-VII secolo', '2', '', '[[''Coperto da'', ''492''], [''Coperto da'', ''762''], [''Copre'', ''567''], [''Copre'', ''770''], [''Copre'', ''799''], [''Copre'', ''817''], [''Si appoggia a'', ''591''], [''Tagliato da'', ''561''], [''Tagliato da'', ''800''], [''Uguale a'', ''566'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '715', 'US', 'Struttura in laterizi  rubefatti, individuato nel Settore 2b, nella parte più interna della fornace STR.18, costituito da un filare di mattoni non integri, ma tagliati per adattarsi all''andamento circolare della struttura, disposti su sei corsi, di cui l''ultimo posto in verticale, per un''altezza complessiva di 0.38 m. L''evidenza non conserva i suoi limiti originari in quanto tagliata da una fossa da grano STR. 19 e dal relativo taglio di spoliazione. Il suo diametro è pari a . Sulla sua superficie sono stati rinvenuti residui della colata di bronzo', '1', '', '[[''Coperto da'', ''672''], [''Coperto da'', ''716''], [''Coperto da'', ''717''], [''Gli si appoggia'', ''718''], [''Gli si appoggia'', ''736''], [''Riempie'', ''241''], [''Riempie'', ''712''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '3', '9', 'US', 'Struttura muraria di forma paralleledipeda, individuata nel Settore 2 e durante la realizzazione dei Saggi 2, 3, 5, 6 e 7. Essa è pertinente al condotto idrico CON_1, presenta un andamento NE/SO ed è costituita da ciottoli e laterizi, sia interi che in frammenti, legati con malta tenace di colore grigiastro. La larghezza della struttura varia al variare della sezione con cunicolo.', '3', '', '[[''Coperto da'', ''3''], [''Coperto da'', ''79''], [''Copre'', ''21''], [''Riempie'', ''8''], [''Si appoggia a'', ''70''], [''Si lega a'', ''12''], [''Si lega a'', ''4''], [''Tagliato da'', ''93''], [''Tagliato da'', ''94''], [''Tagliato da'', ''96'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '208', 'US', 'Riempimento a matrice limo sabbiosa di colore marrone chiaro e consistenza friabile, con frustoli di carbone, lenti di cenere e sporadici frammenti laterizi, pietre e ciottoli fluviali di piccole e medie dimensioni. All''interno del deposito sono stati rinvenuti numerosissimi frammenti ceramici, alcuni dei quali di grandi dimensioni, pertinenti a recipienti in buona parte ricostruibili tra cui boccali in maiolica arcaica, forme aperte e chiuse di ceramica comune, una grande quantità di fauna oltre a recipienti in vetro e reperti metallici', '2', '1', '[[''Coperto da'', ''210''], [''Coperto da'', ''227''], [''Copre'', ''209''], [''Riempie'', ''392''], [''Si appoggia a'', ''167''], [''Si appoggia a'', ''229''], [''Si appoggia a'', ''296''], [''Si appoggia a'', ''390''], [''Tagliato da'', ''170'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '555', 'US', 'Strato di malta idraulica di colore rosato e di consistenza tenace, con andamento tabulare e potenza pari a 0.08 m, individuato al di sopra del piano in laterizi retto da suspensurae che costituisce la pavimentazione dell''ambiente termale TER-1, individuato nel Settore 2b, presso il limite NO dello stesso', '1', '', '[[''Coperto da'', ''510''], [''Copre'', ''568''], [''Copre'', ''569''], [''Si appoggia a'', ''497''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''499''], [''Si appoggia a'', ''500''], [''Si appoggia a'', ''538''], [''Si lega a'', ''592'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '732', 'US', 'Taglio individuato nel Settore 1, in sezione durante lo scavo del Saggio 1, successivamente documentato in pianta, ma non ulteriormente indagato in maniera stratigrafica. L''evidenza presenta una forma irregolare in pianta, vagamente sub circolare, di larghezza massima pari a 2 m, con pareti oblique e fondo leggermente concavo, con una profondità massima documentata pari a 0.6 m, ma va ricordato che essa è stata rasata in superficie in corso di sbancamento', '3', '3', '[[''Riempito da'', ''50''], [''Riempito da'', ''731''], [''Taglia'', ''100''], [''Taglia'', ''186''], [''Taglia'', ''52''], [''Taglia'', ''63''], [''Taglia'', ''64''], [''Taglia'', ''65''], [''Taglia'', ''76''], [''Taglia'', ''98''], [''Taglia'', ''99'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '868', 'US', 'Riempimento a matrice limo sabbiosa di colore grigio scuro e consistenza friabile, con sporadici frammenti laterizi, pietre e ciottoli fluviali di piccole e medie dimensioni, malta, sia sciolta che in grumi, e numerose radici, individuato all''interno della sepoltura multipla TB22, nella porzione N del Settore 3, di fronte a S. Colomba. Lo scavo del deposito, il cui spessore varia da 0.2 a 0,3 m, ha restituito numerosi reperti osteologici umani disconnessi, sia integri che frammentari. Il riempimento è stato intercettato presso il limite SE dallo scavo per la fibra ottica e all''angolo S dal passaggio della vecchia fogna, la stessa che taglia altre sepolture documentate in quest''area (TB2 - TB11). Inoltre, data la presenza delle radici di un platano sottoposto a vincolo, non è stato possibile asportare la porzione S del riempimento', '2', '1', '[[''Coperto da'', ''863''], [''Coperto da'', ''865''], [''Coperto da'', ''866''], [''Coperto da'', ''867''], [''Copre'', ''869''], [''Copre'', ''870''], [''Copre'', ''871''], [''Copre'', ''872''], [''Riempie'', ''858''], [''Si appoggia a'', ''857'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '786', 'US', ' Lacerto di struttura in laterizi posti di lista, per lo più integri, ma presenti anche in frammenti, legati con malta di colore giallastro piuttosto tenace, con inclusi millimetrici e centimetrici, non visibile in pianta, in quanto coperto dai muri US 606 e 613, individuato nella parte centrale del Settore 2b, presso il limite NO, durante l''esecuzione del Saggio 16. La struttura è costiuita da due corsi di mattoni e non conserva i limiti originari in quanto tagliata da una grande buca (US 790)', '2', '', '[[''Coperto da'', ''613''], [''Coperto da'', ''747''], [''Copre'', ''749''], [''Gli si appoggia'', ''788''], [''Si appoggia a'', ''626''], [''Si lega a'', ''746''], [''Si lega a'', ''748''], [''Si lega a'', ''787''], [''Tagliato da'', ''790'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '838', 'USM', 'Struttura realizzata con andamento NO/SE, individuata in pianta nella parte centrale del Settore 2b, durante l''ampliamento del limite  NO, realizzata in mattoni sia integri che frammentari, posti di principalmente di lista, ma presenti anche di testa, legati con malta di colore biancastro, con inclusi millimetrici e centimetrici. La muratura prosegue oltre la sezione NO e l''asportazione parziale dei riempimenti ne ha messo in luce 11 corsi piuttosto regolari e un tratto di altezza pari a circa 0.5 m in cui essi non sono distinguibili per la presenza di abbondante malta. In pianta si documenta un tratto di misure pari a  0.38 m di larghezza massima, 1.05 m di lunghezza massima, per un''altezza interna di 1.2 m. Del paramento esterno sono stati messi in luce tre corsi, il più profondo dei quali potrebbe rappresentare la risega di fondazione della struttura, di cui non è stato rinvenuto il taglio di fondazione per la mancata asportazione dello strato soprastante (US 586). Tra le tipologie costruttive documentate in corso di scavo, USM 838 è ascrivibile alla 1a', '1', '', '[[''Gli si appoggia'', ''586''], [''Gli si appoggia'', ''842''], [''Gli si appoggia'', ''843''], [''Gli si appoggia'', ''845''], [''Gli si appoggia'', ''849''], [''Riempie'', ''876''], [''Si lega a'', ''839''], [''Tagliato da'', ''703'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '392', 'US', 'Taglio di forma subrettangolare, individuato nel Settore 4, all''interno del quale sono stati realizzati controterra i due muri USM 167 e USM 390, che assieme a strutture preesistenti, formano il butto STR. 9. Il taglio è stato documentato in pianta e non indagato in sezione, ma è presumibile che presenti le pareti verticali e il fondo piatto. Le dimensioni dell''evidenza sono pari a 1.96 di lunghezza e 1.78 di larghezza, per una profondità massima di 1.1 m', '2', '1', '[[''Riempito da'', ''167''], [''Riempito da'', ''208''], [''Riempito da'', ''209''], [''Riempito da'', ''210''], [''Riempito da'', ''227''], [''Riempito da'', ''390''], [''Riempito da'', ''464''], [''Taglia'', ''226''], [''Taglia'', ''229'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '382', 'US', 'Taglio di forma rettilinea, con andamento NE/SO, individuata nel Settore 2, in corrispondenza della prosecuzione verso S del muro US 265. Lo scavo ha messo in luce una fossa con pareti verticali e fondo piatto, di dimensioni pari a 5.15 x 0.8, e di profondità pari a 0.85 m, che non conserva i limiti originari in quanto tagliato da buche e fosse successive. Sul fondo del taglio è stata individuata la fondazione US 425', '2', '', '[[''Riempito da'', ''381''], [''Taglia'', ''250''], [''Taglia'', ''265''], [''Taglia'', ''425''], [''Taglia'', ''427''], [''Taglia'', ''490''], [''Taglia'', ''491''], [''Taglia'', ''492''], [''Tagliato da'', ''351''], [''Tagliato da'', ''396'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '536', 'US', 'Riempimento a matrice limo sabbiosa di colore marrone e consistenza friabile, con sporadici frammenti laterizi, pietre e ciottoli fluviali di piccole e medie dimensioni, individuato nel Settore 3 durante lo scavo per la messa in opera della fogna, all''interno di una cassa in laterizi, tagliata dal passaggio di un sottoservizio contemporaneo, così come i suoi diversi riempimenti. Il deposito risulta inoltre tagliato dalla sepoltura TB14', '2', '1', '[[''Coperto da'', ''522''], [''Coperto da'', ''531''], [''Copre'', ''537''], [''Copre'', ''541''], [''Riempie'', ''526''], [''Si appoggia a'', ''524''], [''Si appoggia a'', ''525''], [''Si appoggia a'', ''530''], [''Tagliato da'', ''529'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '701', 'US', 'Riempimento a matrice limosa grigio scuro e consistenza friabile, a tessitura fine, con frustoli di carbone, sporadici frammenti laterizi, individuato nel Settore 2b, all''interno della fornace da campana STR. 18, addossato alla parete N della stessa.', '1', '1', '[[''Coperto da'', ''691''], [''Coperto da'', ''711''], [''Copre'', ''672''], [''Copre'', ''728''], [''Riempie'', ''241''], [''Si appoggia a'', ''733''], [''Si appoggia a'', ''734''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '569', 'US', 'Laterizi in frammenti di piccole dimensioni, legati con malta idraulica di colore rosato e consistenza compatta, individuati nel Settore 2b, all''interno del vano TER-1, sui quattro lati dell''ambiente, tra i muri perimetrali e il piano sospeso su suspensurae ', '1', '', '[[''Coperto da'', ''510''], [''Coperto da'', ''555''], [''Si appoggia a'', ''497''], [''Si appoggia a'', ''498''], [''Si appoggia a'', ''499''], [''Si appoggia a'', ''500''], [''Si appoggia a'', ''538''], [''Si appoggia a'', ''568'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '355', 'US', 'Strato a matrice limosa di colore marrone chiaro e consistenza compatta, con un''alta percentuale di calce rosata a granulometria molto fine e lenti di cenere, individuato in maniera piuttosto omogenea all''interno della STR. 26, con andamento tabilare e spesso di qualche cm', '2', '1', '[[''Coperto da'', ''250''], [''Coperto da'', ''336''], [''Coperto da'', ''356''], [''Copre'', ''354''], [''Copre'', ''412''], [''Tagliato da'', ''367''], [''Tagliato da'', ''384''], [''Tagliato da'', ''386''], [''Tagliato da'', ''608'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '718', 'US', 'Riempimento a matrice limo argillosa di colore marrone e consistenza poco compatta, con carbone, concotto in grumi e piccoli frammenti di laterizi in dispersione, individuato nella parte centrale della fornace da campana STR. 18, messa in luce nel Settore 2b. L''evidenza non conserva i suoi limiti originari in quanto tagliata da una fossa da grano STR. 19 e dal relativo taglio di spoliazione. La sua potenza massima documentata è pari a 0.26 m', '1', '', '[[''Coperto da'', ''672''], [''Coperto da'', ''726''], [''Coperto da'', ''735''], [''Copre'', ''736''], [''Riempie'', ''241''], [''Riempie'', ''712''], [''Si appoggia a'', ''715''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '726', 'US', 'Riempiemento a matrice limo argillosa di colore marrone e consistenza compatta, con frammenti decimetrici e centimetrici di laterizi, pietre di piccola pezzatura, frustoli di carbone e grumi di concotto, individuato nel Settore 2b, all''interno della fornace da campana STR. 18. Il deposito, di potenza massima di 0.45 m, non conserva i limiti originari in quanto tagliato per la messa in opera della fossa da grano STR. 19 e dal relativo taglio di spoliazione', '1', '', '[[''Coperto da'', ''242''], [''Coperto da'', ''671''], [''Coperto da'', ''672''], [''Copre'', ''718''], [''Copre'', ''735''], [''Riempie'', ''241''], [''Si appoggia a'', ''734''], [''Tagliato da'', ''674''], [''Tagliato da'', ''723'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '292', 'US', 'Strato di sabbia a granulometria millimetrica, di colore marrone chiaro e consistenza compatta, con malta sciolta, ciottoli e frammenti laterizi di dimensioni centimetriche, individuato al di sopra della strada US 349. Durante la sua asportazione sono stati recuperati diversi frammenti ceramici e una moneta databili tra la fine del XIV e il XVI secolo', '1', '2', '[[''Coperto da'', ''491''], [''Copre'', ''349''], [''Copre'', ''498''], [''Copre'', ''499''], [''Copre'', ''500''], [''Copre'', ''510''], [''Copre'', ''538''], [''Copre'', ''573''], [''Tagliato da'', ''513''], [''Tagliato da'', ''548'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '783', 'USM', 'Unità stratigrafica muraria pertinente al paramento interno del muro perimetrale SE dell''ambiente termale STR. 29, individuato nella parte centrale del Settore 2b, nella porzione NO dello stesso. La struttura segue andamento NE/SO ed è realizzata in mattoni sia integri che frammentari, posti principalmente di lista, ma presenti anche di testa, legati con malta tenace di colore giallastro e posti su filari orizzontali piuttosto regolari, con eccezioni puntuali. Il muro si conserva per otto corsi regolari, documentati nel paramento interno. Le sue dimensioni visibili in pianta sono pari a 0.53 m di larghezza massima, 1 m di lunghezza massima e 0.64 m di altezza. Data la frammentarietà degli elementi costitutivi, non è possibile riconoscerne il modulo, il quale doveva essere vario, considerato il largo impiego di materiale di riutilizzo: lo spessore degli elementi varia da 5.5 a 7 cm, mentre le altre dimensioni non sono verificabili. Tra le tipologie costruttive documentate in corso di scavo, USM 783 è ascrivibile alla 3', '2', '', '[[''Coperto da'', ''492''], [''Copre'', ''789''], [''Gli si appoggia'', ''499''], [''Gli si appoggia'', ''612''], [''Gli si appoggia'', ''758''], [''Gli si appoggia'', ''779''], [''Si lega a'', ''500''], [''Si lega a'', ''780'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '705', 'US', 'Strato a matrice limosa di colore marrone scuro e consistenza compatta, con una buona percentuale di sabbia a granulometria medio/grande e lenti di sabbia a tessitura più fine, con malta sciolta, sporadici laterizi in frammenti e pietre di piccole e medie dimensioni, di potenza massima documentata pari a 0.6 m, individuato in sezione durante lo scavo del Saggio 16 e asportato mediante l''uso del mezzo meccanico. Lo scavo ha restituito una certa quantità di frammenti ceramici, tra cui un puntale di spatheion databile al V secolo e un frammento di spalla di LRA 7-2.3 databile tra la prima metà e la metà del VII sec. d.C.', '1', '', '[[''Coperto da'', ''611''], [''Coperto da'', ''704''], [''Copre'', ''626''], [''Copre'', ''709''], [''Copre'', ''737''], [''Tagliato da'', ''548''], [''Tagliato da'', ''708''], [''Tagliato da'', ''750''], [''Tagliato da'', ''790'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '809', 'US', 'Strato di cocciopesto di colore bruno, in buono stato di conservazione, individuato nel Settore 2b, all''interno dell''ambiente termale STR. 29. L''evidenza occupa tutta l''area del vano, il quale prosegue oltre il limite di scavo NO ', '2', '2', '[[''Coperto da'', ''612''], [''Coperto da'', ''807''], [''Coperto da'', ''808''], [''Si appoggia a'', ''781''], [''Si appoggia a'', ''789''], [''Si appoggia a'', ''801''], [''Si appoggia a'', ''802''], [''Si lega a'', ''811'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '634', 'US', 'Taglio di forma subcircolare, profilo e andamento regolari, con pareti oblique e fondo concavo, individuato nel Settore 2b al di sopra del muro S della STR. 16. Il taglio, di diametro pari a 0.6 e profondità massima di 0.15 non conserva i limiti originari, rasato in superficie in fase di sbancamento e intercettato dal taglio di una buca contemporanea non riportata in pianta', '1', '1', '[[''Riempito da'', ''633''], [''Taglia'', ''492''], [''Taglia'', ''581''], [''Taglia'', ''582''], [''Taglia'', ''597''], [''Taglia'', ''601''], [''Taglia'', ''602''], [''Taglia'', ''603''], [''Taglia'', ''635''], [''Taglia'', ''636'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '278', 'US', 'Riempimento a matrice sabbiosa di colore marrone chiaro e consistenza friabile, con numerosi frammenti laterizi, ciottoli fluviali di medie e piccole dimensioni, pietre e malta sia sciolta che in grumi. Durante la sua asportazione, inizialmente manuale e inseguito a mezzo meccanico, sono stati recuperati diversi frammenti ceramici, tra cui ceramica arcaica e invetriata databile al XIV secolo, fauna e reperti metallici. Con lo scavo, per ragioni di sicurezza, non è stato raggiunto il fondo della struttura, ma ci si è fermati alla profondità di 1.6 m dalla quota di sbancamento', '1', '1', '[[''Coperto da'', ''451''], [''Riempie'', ''279''], [''Si appoggia a'', ''304''], [''Si appoggia a'', ''313''], [''Si appoggia a'', ''314''], [''Si appoggia a'', ''337''], [''Tagliato da'', ''329''], [''Tagliato da'', ''333'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '232', 'US', 'Strato eterogeneo, a matrice prevalentemente sabbiosa di colore marrone chiaro e consistenza friabile, con lenti di argilla, ghiaia in dispersione, ciottoli fluviali di piccole e medie dimensioni, frammenti laterizi e malta, sia sciolta che in grumi, individuato nella porzione N del Settore 4, tra il muro del fossato US 146 e il butto strutturale STR. 9', '1', '', '[[''Coperto da'', ''153''], [''Coperto da'', ''52''], [''Copre'', ''166''], [''Copre'', ''167''], [''Copre'', ''210''], [''Copre'', ''226''], [''Copre'', ''302''], [''Copre'', ''390''], [''Copre'', ''391''], [''Tagliato da'', ''231'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '279', 'US', 'Taglio di forma subrettangolare, nel Settore 2, immediatamente a SE rispetto alla STR. 11 = CAS-1 e non ulteriormente indagato', '2', '1', '[[''Riempito da'', ''278''], [''Riempito da'', ''304''], [''Riempito da'', ''313''], [''Riempito da'', ''314''], [''Riempito da'', ''337''], [''Taglia'', ''15''], [''Taglia'', ''289''], [''Taglia'', ''511''], [''Taglia'', ''518'']]');
INSERT INTO us_table (sito, area, us, unita_tipo, descrizione, fase_iniziale, fase_finale, rapporti) VALUES ('RegressionFixture_v1', '1', '530', 'US', 'Struttura con andamento N/S, individuata nella parte centrale del Settore 3 durante lo scavo per la nuova rete fognaria. Il muro, costituito da un unico filare realizzato con laterizi, principalmente in frammenti e posti di lista, ciottoli fluviali ed elementi lapidei di reimpiego legati con una malta grossolana di colore giallastro poco tenace, con inclusi millimetrici e centimetrici, non conserva i limiti originari, perché tagliato a N dalla sepoltura TB14. Della struttura, che si lega a N con il muro US 524 e a E con il muro US 525, si conservano otto corsi piuttosto regolari per un tratto misure pari a 0.58 x 0.18 m, e un''altezza di circa 0.7 m', '2', '1', '[[''Coperto da'', ''96''], [''Gli si appoggia'', ''522''], [''Gli si appoggia'', ''536''], [''Gli si appoggia'', ''541''], [''Riempie'', ''526''], [''Si lega a'', ''524''], [''Si lega a'', ''525''], [''Tagliato da'', ''529'']]');
